using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpToolsDemo;

/// <summary>
/// MCP tool class that wraps a weather REST API.
/// The SDK creates a new instance per tool invocation, resolving constructor
/// parameters from the DI container each time.
/// </summary>
[McpServerToolType]
public class WeatherTools
{
    private readonly HttpClient _http;

    // Constructor-injected HttpClient — resolved from DI via IHttpClientFactory.
    // Each tool method invocation gets a fresh WeatherTools instance with its
    // own HttpClient, so there's no shared mutable state to worry about.
    public WeatherTools(HttpClient http)
    {
        _http = http;
    }

    [McpServerTool(Name = "get_weather", Title = "Get Weather",
        ReadOnly = true, Destructive = false, OpenWorld = true)]
    [Description("Gets the current weather for a city. Returns temperature, conditions, and humidity.")]
    public async Task<string> GetWeatherAsync(
        [Description("City name, e.g. 'Seattle' or 'London'")] string city,
        [Description("Unit system: 'metric' or 'imperial' (default: metric)")] string units = "metric",
        CancellationToken cancellationToken = default)
    {
        var url = $"https://api.weatherapi.com/v1/current.json?q={Uri.EscapeDataString(city)}&units={units}";

        var response = await _http.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);

        var location = json.GetProperty("location").GetProperty("name").GetString();
        var temp = json.GetProperty("current").GetProperty("temp_c").GetDouble();
        var condition = json.GetProperty("current").GetProperty("condition").GetProperty("text").GetString();
        var humidity = json.GetProperty("current").GetProperty("humidity").GetInt32();

        return $"Weather in {location}: {temp}°C, {condition}, Humidity: {humidity}%";
    }

    [McpServerTool(Name = "get_forecast", Title = "Get Forecast",
        ReadOnly = true, Destructive = false)]
    [Description("Gets a multi-day weather forecast for a city.")]
    public async Task<string> GetForecastAsync(
        [Description("City name")] string city,
        [Description("Number of forecast days (1-7)")] int days = 3,
        CancellationToken cancellationToken = default)
    {
        days = Math.Clamp(days, 1, 7);
        var url = $"https://api.weatherapi.com/v1/forecast.json?q={Uri.EscapeDataString(city)}&days={days}";

        var response = await _http.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);

        var forecastDays = json.GetProperty("forecast").GetProperty("forecastday");
        var lines = new List<string> { $"Forecast for {city} ({days} days):" };

        foreach (var day in forecastDays.EnumerateArray())
        {
            var date = day.GetProperty("date").GetString();
            var maxTemp = day.GetProperty("day").GetProperty("maxtemp_c").GetDouble();
            var minTemp = day.GetProperty("day").GetProperty("mintemp_c").GetDouble();
            var condition = day.GetProperty("day").GetProperty("condition").GetProperty("text").GetString();
            lines.Add($"  {date}: {minTemp}–{maxTemp}°C, {condition}");
        }

        return string.Join("\n", lines);
    }
}

