         var url = $"https://api.weatherapi.com/v1/forecast.json?q={Uri.EscapeDataString(city)}&days={days}";

         var response = await _http.GetAsync(url, cancellationToken);
         response.EnsureSuccessStatusCode();

         var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);

         var forecastDays = json.GetProperty("forecast").GetProperty("forecastday");
         var lines = new List<string> { $"Forecast for {city} ({days} days):" };

         foreach (var day in forecastDays.EnumerateArray())
         {
             var date = day.GetProperty("date").GetString();
             var maxTemp = day.GetProperty("day").GetProperty("maxtemp_c").GetDouble();
             var minTemp = day.GetProperty("day").GetProperty("mintemp_c").GetDouble();
             var condition = day.GetProperty("day").GetProperty("condition").GetProperty("text").GetString();
             lines.Add($"  {date}: {minTemp}–{maxTemp}°C, {condition}");
         }

         return string.Join("\n", lines);
     }
 }
